#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int N, Q;
    scanf("%d", &N);
    int* A = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int X, Y;
            scanf("%d %d", &X, &Y);
            A[X - 1] = Y;
        } else {
            int L, R, G;
            scanf("%d %d %d", &L, &R, &G);
            int count = 0;
            for (int j = L - 1; j < R; j++) {
                if (gcd(G, A[j]) == 1) count++;
            }
            printf("%d\n", count);
        }
    }
    free(A);
    return 0;
}

