import java.util.Scanner;

public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        int Q = sc.nextInt();
        for (int i = 0; i < Q; i++) {
            int type = sc.nextInt();
            if (type == 1) {
                int X = sc.nextInt();
                int Y = sc.nextInt();
                A[X - 1] = Y;
            } else {
                int L = sc.nextInt();
                int R = sc.nextInt();
                int G = sc.nextInt();
                int count = 0;
                for (int j = L - 1; j < R; j++) {
                    if (gcd(G, A[j]) == 1) count++;
                }
                System.out.println(count);
            }
        }
    }
}

